```tsx
function replaceRequestBody<T extends IncomingMessage>(
  base: T,
  body: BodyStream
): T {
  const stream = bodyStreamToNodeStream(body)

  for (const key in stream) {
    let v = stream[key as keyof NodeStreams.Readable] as any
    if (typeof v === 'function') {
      v = v.bind(stream)
    }
    base[key as keyof T] = v
  }

  return base
}
